(() => { const panel = document.getElementById('opsHealthPanel'); if (!panel) return; const runBtn = document.getElementById('opsHealthRun'); const badge = document.getElementById('opsHealthBadge'); const summary = document.getElementById('opsHealthSummary'); const stats = document.getElementById('opsHealthStats'); const pagesBody = document.getElementById('opsHealthPages'); const assetsBody = document.getElementById('opsHealthAssets'); const providersBody = document.getElementById('opsHealthProviders'); const criticalPages = [ { path: '/', label: '메인', expect: ['home-provider-rotator-grid', '대표 글 6개'] }, { path: '/blog/', label: '블로그 허브', expect: ['대표 글', '필요한 주제부터 바로 내려가서 확인'] }, { path: '/tools/', label: '도구 허브', expect: ['대표 6개', '핵심 도구'] }, { path: '/guaranteed/', label: '보증업체', expect: ['❤️ 여왕벌 ❤️', 'Any Bet', 'UDT', '❤️ SK 홀딩스 ❤️'] }, { path: '/blog/guaranteed-before-click-checks/', label: '대표 글 상세', expect: ['article-single'] }, { path: '/tools/ai-domain-analysis/', label: '대표 도구 상세', expect: ['tool-detail-card'] } ]; const icon = (ok) => ok ? 'OK' : 'FAIL'; const esc = (value) => String(value ?? '').replace(/[&<>'"]/g, (ch) => ({ '&':'&amp;','<':'&lt;','>':'&gt;', '"':'&quot;', "'":'&#39;' }[ch])); async function fetchText(url){ const res = await fetch(url, { cache:'no-store', credentials:'same-origin' }); return { ok: res.ok, status: res.status, text: await res.text().catch(() => '') }; } async function fetchJson(url){ const res = await fetch(url, { cache:'no-store', credentials:'same-origin' }); return { ok: res.ok, status: res.status, json: await res.json().catch(() => ({})) }; } function setBadge(ok, text){ if (!badge) return; badge.textContent = text; badge.style.background = ok ? 'rgba(16,185,129,.12)' : 'rgba(239,68,68,.12)'; badge.style.borderColor = ok ? 'rgba(16,185,129,.35)' : 'rgba(239,68,68,.35)'; badge.style.color = ok ? '#065f46' : '#991b1b'; } function rowHtml(ok, name, detail){ return `<tr><td><span class="opsBadge" style="background:${ok ? 'rgba(16,185,129,.12)' : 'rgba(239,68,68,.12)'};border-color:${ok ? 'rgba(16,185,129,.35)' : 'rgba(239,68,68,.35)'};color:${ok ? '#065f46' : '#991b1b'}">${icon(ok)}</span></td><td>${esc(name)}</td><td>${detail}</td></tr>`; } function statHtml(label, value, meta){ return `<div class="opsStat"><div class="k">${esc(label)}</div><div class="v">${esc(value)}</div><div class="m">${esc(meta)}</div></div>`; } async function runHealth(){ runBtn.disabled = true; setBadge(true, '실행 중'); if (summary) summary.textContent = '핵심 페이지, provider 자산, build/version, sitemap 상태를 확인하고 있습니다.'; if (stats) stats.innerHTML = statHtml('상태', '점검 중', '동일 출처 no-store 기준으로 다시 확인합니다.'); const [buildRes, sitemapRes, providersRes, homeRes] = await Promise.all([ fetchText('/build.txt').catch(() => ({ ok:false, status:0, text:'' })), fetchText('/sitemap.xml').catch(() => ({ ok:false, status:0, text:'' })), fetchJson('/assets/data/guaranteed.providers.v1.20260330.json').catch(() => ({ ok:false, status:0, json:{} })), fetchText('/').catch(() => ({ ok:false, status:0, text:'' })) ]); const pageChecks = []; for (const item of criticalPages){ const result = await fetchText(item.path).catch(() => ({ ok:false, status:0, text:'' })); const markersOk = result.ok && item.expect.every((token) => result.text.includes(token)); pageChecks.push({ ok: result.ok && markersOk, label: item.label, status: result.status, path: item.path, detail: result.ok ? (markersOk ? '응답/핵심 마커 정상' : '응답은 정상이지만 기대 마커 일부 누락') : '응답 실패' }); } const providers = Array.isArray(providersRes.json?.providers) ? providersRes.json.providers : []; const providerChecks = []; for (const item of providers){ const image = item.imageUrl || ''; const imageResult = image ? await fetchText(image).catch(() => ({ ok:false, status:0, text:'' })) : { ok:false, status:0, text:'' }; providerChecks.push({ ok: Boolean(item.officialUrl && item.code && imageResult.ok), name: item.name || item.slug || 'provider', detail: `${item.officialUrl || '-'} · code ${item.code || '-'} · img ${imageResult.status || 0}` }); } const sitemapCount = sitemapRes.ok ? (sitemapRes.text.match(/<loc>/g) || []).length : 0; const buildText = buildRes.text.trim() || 'build 정보 없음'; const assetFiles = Array.from(new Set((homeRes.text.match(/\/assets\/(?:css|js)\/[^"']+/g) || []).map((v) => v.replace('/assets/','assets/')))).slice(0, 14); const pageOk = pageChecks.filter((item) => item.ok).length; const providerOk = providerChecks.filter((item) => item.ok).length; const overallOk = pageOk === pageChecks.length && providerOk === providerChecks.length && sitemapRes.ok && buildRes.ok; if (pagesBody) pagesBody.innerHTML = pageChecks.map((item) => rowHtml(item.ok, item.label, `${esc(item.path)} · HTTP ${item.status} · ${esc(item.detail)}`)).join(''); if (providersBody) providersBody.innerHTML = providerChecks.map((item) => rowHtml(item.ok, item.name, esc(item.detail))).join(''); if (assetsBody) { const rows = [ rowHtml(buildRes.ok, 'build.txt', esc(buildText)), rowHtml(sitemapRes.ok, 'sitemap.xml', `${sitemapCount}개 URL 감지`), ...assetFiles.map((file) => rowHtml(true, 'asset version', esc(file))) ]; assetsBody.innerHTML = rows.join(''); } if (stats) { stats.innerHTML = [ statHtml('핵심 페이지', `${pageOk}/${pageChecks.length}`, '메인 · 허브 · 대표 상세 응답과 마커 확인'), statHtml('보증업체 자산', `${providerOk}/${providerChecks.length}`, '공식 주소 · 가입코드 · 대표 이미지 응답 확인'), statHtml('사이트맵', sitemapRes.ok ? `${sitemapCount} URL` : '점검 필요', '현재 배포된 sitemap.xml 직접 확인'), statHtml('버전 문자열', buildRes.ok ? '정상' : '점검 필요', buildText) ].join(''); } setBadge(overallOk, overallOk ? '정상' : '확인 필요'); if (summary) summary.textContent = overallOk ? '핵심 페이지, provider 자산, build/version, sitemap 상태가 모두 정상입니다.' : '일부 항목에 재확인이 필요합니다. 아래 표에서 FAIL 행만 먼저 보면 됩니다.'; runBtn.disabled = false; } if (runBtn) runBtn.addEventListener('click', runHealth); const consoleEl = document.getElementById('opsConsole'); if (consoleEl) { const observer = new MutationObserver(() => { if (!consoleEl.hasAttribute('hidden') && !panel.dataset.autorunDone) { panel.dataset.autorunDone = '1'; runHealth(); } }); observer.observe(consoleEl, { attributes:true, attributeFilter:['hidden'] }); }
})();
